import React, { useEffect } from 'react';
import { Box, Card, Chip, Divider, IconButton, Typography } from '@mui/material';
import { searchResultContainer } from './AttendeeCard.styles';
import { StatusMessage } from '@/components/StatusMessage';
import { EventActionDialog } from '@/components/EventActionDialog';
import { DonationDialog } from '@/components/DonationDialog';
import { initialStateData, StateData, useLoadingStore } from '@/store';
import { AttendeeServices, AttendeeServicesError } from '@/api';
import { ApiComponentStateManager } from '@/lib/api-state';
import { getEventId } from '@/constants/ApiConstants';
import { CallStatus } from '@/types/api.types';
import PlaceIcon from "@mui/icons-material/Place";
import WorkIcon from "@mui/icons-material/Work";
import SchoolIcon from "@mui/icons-material/School";
import PhoneIcon from '@mui/icons-material/Phone';
import EmailIcon from '@mui/icons-material/Email';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import TaskAltIcon from '@mui/icons-material/TaskAlt';
import HowToRegIcon from '@mui/icons-material/HowToReg';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import CancelIcon from '@mui/icons-material/Cancel';
import DeleteForeverIcon from '@mui/icons-material/DeleteForever';
import EditIcon from '@mui/icons-material/Edit';
import GroupIcon from '@mui/icons-material/Group';
import CalendarMonthIcon from '@mui/icons-material/CalendarMonth';
import RestaurantIcon from '@mui/icons-material/Restaurant';
import { AttendeeData } from '@/types/attendee.types';
import { useSelectedEventContext } from '@/hooks/useSelectedEventContext';
import { compactChipSx } from '@/constants/ThemeConstants';
import { calculateDonationTotal } from '@/utils/eventCalculations';
import { logger } from '@/utils/logger';

/** Compact icon + text row with tinted icon */
const InfoRow: React.FC<{ icon: React.ReactNode; children: React.ReactNode }> = ({ icon, children }) => (
    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75, minWidth: 0, py: 0.15 }}>
        <Box sx={{ color: 'action.active', display: 'flex', flexShrink: 0 }}>{icon}</Box>
        <Typography variant="body2" sx={{ fontSize: '0.8125rem', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {children}
        </Typography>
    </Box>
);

interface AttendeeCardProps {
    attendee: AttendeeData;
    onCheckIn?: (attendeeId: string) => void; // Make optional since we'll handle internally
    onCancelRegistration?: (attendeeId: string) => void; // Callback to remove attendee from parent list
}

export const AttendeeCard: React.FC<AttendeeCardProps> = ({ attendee, onCheckIn, onCancelRegistration }) => {
    const [checkInState, setCheckInState] = React.useState<StateData<boolean>>(initialStateData(false));
    const [cancelState, setCancelState] = React.useState<StateData<boolean>>(initialStateData(false));
    const [deleteState, setDeleteState] = React.useState<StateData<boolean>>(initialStateData(false));
    const [updateState, setUpdateState] = React.useState<StateData<AttendeeData>>(initialStateData<AttendeeData>());
    const [donationState, setDonationState] = React.useState<StateData<AttendeeData>>(initialStateData<AttendeeData>());
    const [localAttendee, setLocalAttendee] = React.useState<AttendeeData>(attendee);
    const [openCancelDialog, setOpenCancelDialog] = React.useState<boolean>(false);
    const [openDeleteDialog, setOpenDeleteDialog] = React.useState<boolean>(false);
    const [openCheckInDialog, setOpenCheckInDialog] = React.useState<boolean>(false);
    const [openUpdateDialog, setOpenUpdateDialog] = React.useState<boolean>(false);
    const [openDonationDialog, setOpenDonationDialog] = React.useState<boolean>(false);
    const { selectedEvent } = useSelectedEventContext();
    const { setLoading } = useLoadingStore();

    // Check if check-in is enabled for the selected event
    const isCheckinEnabled = selectedEvent?.isCheckinEnabled ?? false;

    // Get food options from selected event's food field (comma-separated)
    const foodOptions = React.useMemo(() => {
        if (selectedEvent?.food && selectedEvent?.isFoodEnabled) {
            return selectedEvent.food.split(',').map((opt: string) => opt.trim()).filter((opt: string) => opt.length > 0);
        }
        return [];
    }, [selectedEvent?.food, selectedEvent?.isFoodEnabled]);

    // Control global loading based on check-in or cancel state
    useEffect(() => {
        if (checkInState.status === CallStatus.InProgress) {
            setLoading(true, 'Checking in...');
        } else if (cancelState.status === CallStatus.InProgress) {
            setLoading(true, 'Cancelling registration...');
        } else if (deleteState.status === CallStatus.InProgress) {
            setLoading(true, 'Deleting attendee...');
        } else if (updateState.status === CallStatus.InProgress) {
            setLoading(true, 'Updating registration...');
        } else if (donationState.status === CallStatus.InProgress) {
            setLoading(true, 'Adding donation...');
        } else {
            setLoading(false);
        }
        
        // Cleanup on unmount
        return () => {
            setLoading(false);
        };
    }, [checkInState.status, cancelState.status, deleteState.status, updateState.status, donationState.status, setLoading]);

    // Update local attendee when prop changes, but preserve check-in state if we just updated it
    React.useEffect(() => {
        if (attendee.userId !== localAttendee.userId || 
            (!localAttendee.checkedInAt && attendee.checkedInAt)) {
            setLocalAttendee(attendee);
        }
    }, [attendee, localAttendee.userId, localAttendee.checkedInAt]);

    const handleCheckInClick = () => {
        setOpenCheckInDialog(true);
    };

    const handleCheckInConfirm = async (foodPreference: string, count: number) => {
        setOpenCheckInDialog(false);
        
        try {
            // First update food/headcount, then check in
            const updatePromise = AttendeeServices.UpdateRegistrationById(getEventId(), attendee.userId, foodPreference, count);
            await updatePromise;
            const checkInPromise = AttendeeServices.CheckInAttendee(getEventId(), attendee.userId, true);
            ApiComponentStateManager(checkInPromise, setCheckInState);
            
            try {
                await checkInPromise;
                setLocalAttendee(prev => ({
                    ...prev,
                    checkedInAt: Date.now(),
                    headCount: count,
                    foodPreference: foodPreference
                }));
            } catch (error) {
                logger.error('AttendeeCard', 'Check-in API call failed', error);
            }
            
            if (onCheckIn) {
                onCheckIn(attendee.userId);
            }
        } catch (error) {
            logger.error('AttendeeCard', 'Error checking in attendee', error);
        }
    };

    const handleCancelClick = () => {
        setOpenCancelDialog(true);
    };

    const handleCancelConfirm = async () => {
        setOpenCancelDialog(false);
        
        try {
            const cancelPromise = AttendeeServices.DeleteRegistrationById(getEventId(), attendee.userId);
            ApiComponentStateManager(cancelPromise, setCancelState);
            
            try {
                await cancelPromise;
                if (onCancelRegistration) {
                    onCancelRegistration(attendee.userId);
                }
            } catch (error) {
                logger.error('AttendeeCard', 'Cancel registration API call failed', error);
            }
        } catch (error) {
            logger.error('AttendeeCard', 'Error canceling registration', error);
        }
    };

    const handleDeleteClick = () => {
        setOpenDeleteDialog(true);
    };

    const handleDeleteConfirm = async () => {
        setOpenDeleteDialog(false);

        try {
            // Invoke admin delete endpoint for complete removal
            const deletePromise = AttendeeServices.DeleteRegistrationById(getEventId(), attendee.userId);
            ApiComponentStateManager(deletePromise, setDeleteState);

            try {
                await deletePromise;
                if (onCancelRegistration) {
                    onCancelRegistration(attendee.userId);
                }
            } catch (error) {
                logger.error('AttendeeCard', 'Delete attendee API call failed', error);
            }
        } catch (error) {
            logger.error('AttendeeCard', 'Error deleting attendee', error);
        }
    };

    const handleUpdateClick = () => {
        setOpenUpdateDialog(true);
    };

    const handleDonationClick = () => {
        setOpenDonationDialog(true);
    };

    const handleDonationConfirm = async (donation: string) => {
        try {
            const donationPromise = AttendeeServices.AddDonation(getEventId(), attendee.userId, donation);
            ApiComponentStateManager(donationPromise, setDonationState);
            try {
                await donationPromise;
                setLocalAttendee(prev => ({
                    ...prev,
                    donation: prev.donation ? `${prev.donation},${donation}` : donation,
                }));
                setOpenDonationDialog(false);
            } catch (error) {
                logger.error('AttendeeCard', 'Add donation API call failed', error);
            }
        } catch (error) {
            logger.error('AttendeeCard', 'Error adding donation', error);
        }
    };

    const handleUpdateConfirm = async (foodPreference: string, count: number) => {
        setOpenUpdateDialog(false);
        
        try {
            const updatePromise = AttendeeServices.UpdateRegistrationById(getEventId(), attendee.userId, foodPreference, count);
            ApiComponentStateManager(updatePromise, setUpdateState);
            
            try {
                await updatePromise;
                setLocalAttendee(prev => ({
                    ...prev,
                    headCount: count,
                    foodPreference: foodPreference
                }));
            } catch (error) {
                logger.error('AttendeeCard', 'Update API call failed', error);
            }
        } catch (error) {
            logger.error('AttendeeCard', 'Error updating registration', error);
        }
    };

    return (
        <>
        <Card
            elevation={3}
            sx={{
                ...searchResultContainer,
                display: 'flex',
                flexDirection: 'column',
                borderRadius: 2,
                transition: 'all 0.2s ease',
                '&:hover': { boxShadow: 4, transform: 'translateY(-2px)' },
            }}
            key={localAttendee.userId}
        >
            {/* Header */}
            <Box sx={{ px: 1.5, pt: 1.25, pb: 0.75 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <Typography variant="subtitle1" sx={{ fontWeight: 600, lineHeight: 1.3, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', mr: 1 }}>
                        {localAttendee.profile?.name}
                    </Typography>
                    {localAttendee.checkedInAt ? (
                        <Chip label="✓ Checked In" size="small" variant="outlined" sx={{ flexShrink: 0, ...compactChipSx }} />
                    ) : (
                        <Chip label={localAttendee.profile?.profileType} size="small" variant="outlined" sx={{ flexShrink: 0, ...compactChipSx }} />
                    )}
                </Box>
            </Box>

            {/* Profile info rows */}
            <Box sx={{ px: 1.5, pb: 0.75, display: 'flex', flexDirection: 'column', gap: 0.25, flex: 1 }}>
                <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 0.25 }}>
                    <InfoRow icon={<SchoolIcon sx={{ fontSize: '1rem' }} />}>{localAttendee.profile?.firstJnvName}</InfoRow>
                    {localAttendee.profile?.batch ? (
                        <InfoRow icon={<CalendarMonthIcon sx={{ fontSize: '1rem' }} />}>Batch {localAttendee.profile.batch}</InfoRow>
                    ) : null}
                </Box>
                {localAttendee.profile?.location && (
                    <InfoRow icon={<PlaceIcon sx={{ fontSize: '1rem' }} />}>{localAttendee.profile.location}</InfoRow>
                )}
                {localAttendee.profile?.organisation && (
                    <InfoRow icon={<WorkIcon sx={{ fontSize: '1rem' }} />}>
                        {localAttendee.profile.jobTitle ? `${localAttendee.profile.jobTitle}, ${localAttendee.profile.organisation}` : localAttendee.profile.organisation}
                    </InfoRow>
                )}
                {(localAttendee.profile?.email || localAttendee.profile?.phone) && (
                    <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 0.25 }}>
                        {localAttendee.profile?.email && (
                            <InfoRow icon={<EmailIcon sx={{ fontSize: '1rem' }} />}>{localAttendee.profile.email}</InfoRow>
                        )}
                        {localAttendee.profile?.phone && (
                            <InfoRow icon={<PhoneIcon sx={{ fontSize: '1rem' }} />}>{localAttendee.profile.phone}</InfoRow>
                        )}
                    </Box>
                )}

                {/* Event-specific info */}
                <Divider sx={{ my: 0.5, borderStyle: 'dashed' }} />
                <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 0.25 }}>
                    <InfoRow icon={<GroupIcon sx={{ fontSize: '1rem', color: 'info.main' }} />}>{localAttendee.headCount ?? 1}</InfoRow>
                    <InfoRow icon={<CurrencyRupeeIcon sx={{ fontSize: '1rem', color: 'secondary.main' }} />}>{calculateDonationTotal(localAttendee.donation)}</InfoRow>
                    {localAttendee.foodPreference && (
                        <InfoRow icon={<RestaurantIcon sx={{ fontSize: '1rem', color: 'warning.main' }} />}>{localAttendee.foodPreference}</InfoRow>
                    )}
                    {localAttendee.checkedInAt && (
                        <InfoRow icon={<TaskAltIcon sx={{ fontSize: '1rem', color: 'success.main' }} />}>
                            {new Date(localAttendee.checkedInAt).toLocaleDateString('en-US', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
                        </InfoRow>
                    )}
                </Box>
            </Box>

            <Divider />

            {/* Actions */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75, px: 1.25, py: 0.75, mt: 'auto', bgcolor: 'grey.50' }}>
                <IconButton
                    size="small"
                    aria-label="delete attendee"
                    onClick={handleDeleteClick}
                    disabled={!!localAttendee.checkedInAt || deleteState.status === CallStatus.InProgress || deleteState.status === CallStatus.Success}
                    color="error"
                    title={localAttendee.checkedInAt ? "Cannot delete checked-in attendee" : "Delete Attendee"}
                >
                    <DeleteForeverIcon sx={{ fontSize: '1.1rem' }} />
                </IconButton>
                <IconButton
                    size="small"
                    aria-label="cancel registration"
                    onClick={handleCancelClick}
                    disabled={!!localAttendee.checkedInAt || cancelState.status === CallStatus.InProgress || cancelState.status === CallStatus.Success}
                    color="warning"
                    title={localAttendee.checkedInAt ? "Cannot cancel checked-in attendee" : "Cancel Registration"}
                >
                    <CancelIcon sx={{ fontSize: '1.1rem' }} />
                </IconButton>

                <IconButton
                    size="small"
                    aria-label="add donation"
                    onClick={handleDonationClick}
                    disabled={donationState.status === CallStatus.InProgress}
                    sx={{ color: 'secondary.main' }}
                    title="Add Donation"
                >
                    <CurrencyRupeeIcon sx={{ fontSize: '1.1rem' }} />
                </IconButton>

                {isCheckinEnabled ? (
                    <IconButton
                        size="small"
                        aria-label={localAttendee.checkedInAt ? "checked in" : "check in"}
                        onClick={handleCheckInClick}
                        disabled={!!localAttendee.checkedInAt || checkInState.status === CallStatus.InProgress}
                        color={localAttendee.checkedInAt ? "success" : "primary"}
                        title={localAttendee.checkedInAt ? "Already Checked In" : "Check In"}
                    >
                        {localAttendee.checkedInAt
                            ? <TaskAltIcon sx={{ fontSize: '1.1rem' }} />
                            : <HowToRegIcon sx={{ fontSize: '1.1rem' }} />
                        }
                    </IconButton>
                ) : (
                    <IconButton
                        size="small"
                        aria-label="update registration"
                        onClick={handleUpdateClick}
                        disabled={updateState.status === CallStatus.InProgress}
                        color="primary"
                        title="Update Registration"
                    >
                        <EditIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                )}

                <Box sx={{ ml: 'auto', display: 'flex', gap: 0.75 }}>
                    <IconButton size="small" aria-label="send email" href={`mailto:${localAttendee.profile?.email}`}>
                        <EmailIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                    <IconButton size="small" aria-label="message on whatsapp" href={`https://wa.me/91${localAttendee.profile?.phone}`} target="_blank" rel="noopener noreferrer">
                        <WhatsAppIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                    <IconButton size="small" aria-label="make phone call" href={`tel:${localAttendee.profile?.phone}`}>
                        <PhoneIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                </Box>
            </Box>

            {checkInState.status === CallStatus.Failure && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage=""
                    failureMessage={AttendeeServicesError.CheckInError(checkInState.httpStatus)}
                    currentStatus={checkInState.status}
                    correlationId={checkInState.correlationId}
                />
            )}
            {(cancelState.status === CallStatus.Success || cancelState.status === CallStatus.Failure) && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage="Registration canceled successfully!"
                    failureMessage={AttendeeServicesError.CancelRegistrationError(cancelState.httpStatus)}
                    currentStatus={cancelState.status}
                    correlationId={cancelState.correlationId}
                />
            )}
            {(deleteState.status === CallStatus.Success || deleteState.status === CallStatus.Failure) && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage="Attendee deleted successfully!"
                    failureMessage={AttendeeServicesError.DeleteRegistrationError(deleteState.httpStatus)}
                    currentStatus={deleteState.status}
                    correlationId={deleteState.correlationId}
                />
            )}
            {(updateState.status === CallStatus.Success || updateState.status === CallStatus.Failure) && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage="Registration updated successfully!"
                    failureMessage={AttendeeServicesError.UpdateRegistrationError(updateState.httpStatus)}
                    currentStatus={updateState.status}
                    correlationId={updateState.correlationId}
                />
            )}
            {(donationState.status === CallStatus.Success || donationState.status === CallStatus.Failure) && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage="Donation added successfully!"
                    failureMessage={AttendeeServicesError.UpdateRegistrationError(donationState.httpStatus)}
                    currentStatus={donationState.status}
                    correlationId={donationState.correlationId}
                />
            )}
        </Card>

        {/* Check-In Dialog */}
        <EventActionDialog
            open={openCheckInDialog}
            actionType="checkin"
            userName={localAttendee.profile?.name ?? ''}
            onClose={() => setOpenCheckInDialog(false)}
            onConfirm={handleCheckInConfirm}
            isFoodEnabled={selectedEvent?.isFoodEnabled}
            isAccompanyEnabled={selectedEvent?.isAccompanyEnabled}
            canBypassAccompanyLimit
            foodOptions={foodOptions}
            initialFoodPreference={attendee.foodPreference || ''}
            initialCount={attendee.headCount ?? 1}
            isLoading={checkInState.status === CallStatus.InProgress}
        />

        {/* Cancel Registration Dialog */}
        <EventActionDialog
            open={openCancelDialog}
            actionType="cancel"
            userName={localAttendee.profile?.name ?? ''}
            onClose={() => setOpenCancelDialog(false)}
            onConfirm={handleCancelConfirm}
            isLoading={cancelState.status === CallStatus.InProgress}
        />

        {/* Delete Attendee Dialog */}
        <EventActionDialog
            open={openDeleteDialog}
            actionType="delete"
            userName={localAttendee.profile?.name ?? ''}
            onClose={() => setOpenDeleteDialog(false)}
            onConfirm={handleDeleteConfirm}
            isLoading={deleteState.status === CallStatus.InProgress}
        />

        {/* Update Registration Dialog */}
        <EventActionDialog
            open={openUpdateDialog}
            actionType="update"
            userName={localAttendee.profile?.name ?? ''}
            onClose={() => setOpenUpdateDialog(false)}
            onConfirm={handleUpdateConfirm}
            isFoodEnabled={selectedEvent?.isFoodEnabled}
            isAccompanyEnabled={selectedEvent?.isAccompanyEnabled}
            canBypassAccompanyLimit
            foodOptions={foodOptions}
            initialFoodPreference={attendee.foodPreference || ''}
            initialCount={attendee.headCount ?? 1}
            isLoading={updateState.status === CallStatus.InProgress}
        />

        {/* Donation Dialog */}
        <DonationDialog
            open={openDonationDialog}
            userName={localAttendee.profile?.name}
            userBatch={localAttendee.profile?.batch}
            existingDonation={localAttendee.donation}
            isSubmitting={donationState.status === CallStatus.InProgress}
            onClose={() => setOpenDonationDialog(false)}
            onConfirm={handleDonationConfirm}
        />
        </>
    );
};