import React, { useEffect } from 'react';
import { Box, Button, Card, Divider, IconButton, Typography } from '@mui/material';
import PlaceIcon from "@mui/icons-material/Place";
import WorkIcon from "@mui/icons-material/Work";
import SchoolIcon from "@mui/icons-material/School";
import LocalLibraryIcon from "@mui/icons-material/LocalLibrary";
import PhoneIcon from '@mui/icons-material/Phone';
import EmailIcon from '@mui/icons-material/Email';
import WhatsAppIcon from '@mui/icons-material/WhatsApp';
import { PublicProfileResult } from '@/types/profile.types';
import { StatusMessage } from '@/components/StatusMessage';
import { EventActionDialog } from '@/components/EventActionDialog';
import { initialStateData, StateData, useLoadingStore } from '@/store';
import { CallStatus } from '@/types/api.types';
import { AttendeeServices, AttendeeServicesError } from '@/api';
import { ApiComponentStateManager } from '@/lib/api-state';
import { getEventId } from '@/constants/ApiConstants';
import { useSelectedEventContext } from '@/hooks/useSelectedEventContext';
import { logger } from '@/utils/logger';
import { getHttpStatus } from '@/utils/apiError';

/** Compact icon + text row with tinted icon */
const InfoRow: React.FC<{ icon: React.ReactNode; children: React.ReactNode }> = ({ icon, children }) => (
    <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.75, minWidth: 0, py: 0.15 }}>
        <Box sx={{ color: 'action.active', display: 'flex', flexShrink: 0 }}>{icon}</Box>
        <Typography variant="body2" sx={{ fontSize: '0.8125rem', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
            {children}
        </Typography>
    </Box>
);

interface ProfileCardProps {
    profile: PublicProfileResult;
    onRegister?: (profileId: string) => void;
    isRegistered?: boolean;
    isRegistrationEnabled?: boolean;
}

export const ProfileCard: React.FC<ProfileCardProps> = React.memo(({ 
    profile, 
    onRegister, 
    isRegistered = false,
    isRegistrationEnabled = true 
}) => {
    const { setLoading } = useLoadingStore();
    const [registerState, setRegisterState] = React.useState<StateData<boolean>>(initialStateData<boolean>());
    const [localIsRegistered, setLocalIsRegistered] = React.useState<boolean>(isRegistered);
    const [openRegistrationDialog, setOpenRegistrationDialog] = React.useState<boolean>(false);
    const { selectedEvent } = useSelectedEventContext();

    // Get food options from selected event's food field (comma-separated) - EXACTLY as configured
    const foodOptions = React.useMemo(() => {
        if (selectedEvent?.food && selectedEvent?.isFoodEnabled) {
            return selectedEvent.food.split(',').map((opt: string) => opt.trim()).filter((opt: string) => opt.length > 0);
        }
        return [];
    }, [selectedEvent?.food, selectedEvent?.isFoodEnabled]);

    useEffect(() => {
        if (registerState.status === CallStatus.InProgress) {
            setLoading(true, 'Registering...');
        } else {
            setLoading(false);
        }
        
        // Cleanup on unmount
        return () => {
            setLoading(false);
        };
    }, [registerState.status, setLoading]);

    // Update local registration state when prop changes
    React.useEffect(() => {
        setLocalIsRegistered(isRegistered);
    }, [isRegistered]);

    const handleRegisterClick = () => {
        setOpenRegistrationDialog(true);
    };

    const handleRegisterConfirm = async (foodPreference: string, count: number) => {
        await handleRegisterWithFood(foodPreference, count);
        setOpenRegistrationDialog(false);
    };

    const handleRegisterWithFood = async (food: string, headCount: number) => {
        try {
            // Call the API directly
            const registerPromise = AttendeeServices.RegisterAttendeeById(getEventId(), profile.id, food, headCount);
            ApiComponentStateManager(registerPromise, setRegisterState);
            
            // Wait for the registration to complete and immediately update local state
            try {
                await registerPromise;
                // Immediately update local state to prevent flicker
                setLocalIsRegistered(true);
            } catch (error) {
                logger.error('ProfileCard', 'Registration API call failed', error);
                
                // Check if it's a 409 conflict (already registered)
                if (getHttpStatus(error) === 409) {
                    // Update local state to show as registered
                    setLocalIsRegistered(true);
                }
                // Don't update local state on other errors
            }
            
            // Also call parent callback if provided
            if (onRegister) {
                onRegister(profile.id);
            }
        } catch (error) {
            console.error('Error registering profile:', error);
        }
    };

    return (
        <Card
            elevation={3}
            sx={{
                minWidth: 275,
                width: 320,
                margin: '5px',
                display: 'flex',
                flexDirection: 'column',
                borderRadius: 2,
                transition: 'all 0.2s ease',
                '&:hover': { boxShadow: 4, transform: 'translateY(-2px)' },
            }}
        >
            {/* Header */}
            <Box sx={{ px: 1.5, pt: 1.25, pb: 0.75 }}>
                <Typography variant="subtitle1" sx={{ fontWeight: 600, lineHeight: 1.3, textAlign: 'center', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {profile.name}
                </Typography>
                {profile.profileType && (
                    <Typography variant="caption" color="text.secondary" sx={{ display: 'block', textAlign: 'center', mt: 0.25 }}>
                        {profile.profileType}
                        {profile.entryYear !== undefined && profile.exitYear !== undefined ? ` · ${profile.entryYear}–${profile.exitYear}` : ''}
                        {profile.batch !== undefined ? ` · Batch ${profile.batch}` : ''}
                    </Typography>
                )}
            </Box>

            {/* Info rows */}
            <Box sx={{ px: 1.5, pb: 1, display: 'flex', flexDirection: 'column', gap: 0.25, flex: 1 }}>
                {profile.firstJnvName && (
                    <InfoRow icon={<SchoolIcon sx={{ fontSize: '1rem' }} />}>{profile.firstJnvName}</InfoRow>
                )}
                {profile.location && (
                    <InfoRow icon={<PlaceIcon sx={{ fontSize: '1rem' }} />}>{profile.location}</InfoRow>
                )}
                {profile.organisation && (
                    <InfoRow icon={<WorkIcon sx={{ fontSize: '1rem' }} />}>
                        {profile.jobTitle ? `${profile.jobTitle}, ${profile.organisation}` : profile.organisation}
                    </InfoRow>
                )}
                {profile.university && (
                    <InfoRow icon={<LocalLibraryIcon sx={{ fontSize: '1rem' }} />}>
                        {profile.degree ? `${profile.degree}, ${profile.university}` : profile.university}
                    </InfoRow>
                )}
            </Box>

            <Divider />

            {/* Actions */}
            <Box sx={{ display: 'flex', alignItems: 'center', px: 1.25, py: 0.75, mt: 'auto', bgcolor: 'grey.50' }}>
                <Button
                    variant="contained"
                    size="small"
                    sx={{ textTransform: 'none', fontSize: '0.75rem', borderRadius: 1.5, fontWeight: 500, px: 1.5 }}
                    onClick={handleRegisterClick}
                    disabled={!isRegistrationEnabled || localIsRegistered || registerState.status === CallStatus.InProgress}
                    color={localIsRegistered ? "success" : "primary"}
                    title={!isRegistrationEnabled ? "Registration is disabled for this event" : undefined}
                >
                    {localIsRegistered ? "✓ Registered" :
                     !isRegistrationEnabled ? "Disabled" : "Register"}
                </Button>
                <Box sx={{ ml: 'auto', display: 'flex', gap: 0.25 }}>
                    <IconButton size="small" aria-label="send email" href={`mailto:${profile.email}`}>
                        <EmailIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                    <IconButton size="small" aria-label="message on whatsapp" href={`https://wa.me/91${profile.phone}`} target="_blank" rel="noopener noreferrer">
                        <WhatsAppIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                    <IconButton size="small" aria-label="make phone call" href={`tel:${profile.phone}`}>
                        <PhoneIcon sx={{ fontSize: '1.1rem' }} />
                    </IconButton>
                </Box>
            </Box>

            {registerState.status === CallStatus.Failure && (
                <StatusMessage
                    notStartedMessage=""
                    successMessage=""
                    failureMessage={AttendeeServicesError.RegisterAttendeeError(registerState.httpStatus)}
                    currentStatus={registerState.status}
                    correlationId={registerState.correlationId}
                />
            )}

            {/* Registration Dialog */}
            <EventActionDialog
                open={openRegistrationDialog}
                actionType="register"
                userName={profile.name ?? ''}
                onClose={() => setOpenRegistrationDialog(false)}
                onConfirm={handleRegisterConfirm}
                isFoodEnabled={selectedEvent?.isFoodEnabled}
                isAccompanyEnabled={selectedEvent?.isAccompanyEnabled}
                foodOptions={foodOptions}
                initialCount={1}
                isLoading={registerState.status === CallStatus.InProgress}
            />
        </Card>
    );
});
ProfileCard.displayName = 'ProfileCard';
