import React from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Button,
    Box,
    TextField,
    Typography,
} from '@mui/material';
import { useBodyScrollLock } from '@/hooks/useBodyScrollLock';
import { calculateDonationTotal } from '@/utils/eventCalculations';

interface DonationDialogProps {
    open: boolean;
    userName?: string;
    userBatch?: number | string;
    existingDonation?: string;
    isSubmitting?: boolean;
    onClose: () => void;
    onConfirm: (donation: string) => void;
}

export const DonationDialog: React.FC<DonationDialogProps> = ({
    open,
    userName,
    userBatch,
    existingDonation,
    isSubmitting = false,
    onClose,
    onConfirm,
}) => {
    const [amount, setAmount] = React.useState('');
    const [txnRef, setTxnRef] = React.useState('');

    useBodyScrollLock(open);

    React.useEffect(() => {
        if (open) {
            setAmount('');
            setTxnRef('');
        }
    }, [open]);

    const existingTotal = React.useMemo(() => calculateDonationTotal(existingDonation), [existingDonation]);

    const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setAmount(e.target.value.replace(/[^0-9]/g, ''));
    };

    const handleSubmit = () => {
        const a = amount.trim();
        const r = txnRef.trim().replace(/\s+/g, '_');
        if (!a || !r) return;
        const amountNum = parseInt(a);
        if (isNaN(amountNum) || amountNum <= 0) return;
        onConfirm(`${a}@${r}`);
    };

    const isValid = !!amount && !!txnRef.trim() && parseInt(amount) > 0;

    return (
        <Dialog open={open} onClose={onClose} maxWidth="xs" fullWidth>
            <DialogTitle>
                Add Donation
                {userName && (
                    <Typography variant="body2" color="text.secondary">
                        {userName}{userBatch !== undefined && userBatch !== '' ? ` (${userBatch})` : ''}
                    </Typography>
                )}
            </DialogTitle>
            <DialogContent>
                {existingDonation && (
                    <Box sx={{ mb: 3, p: 2, backgroundColor: 'action.hover', borderRadius: 1 }}>
                        <Typography variant="body2" color="text.secondary" sx={{ mb: 1, fontWeight: 600 }}>
                            Previous Donations:
                        </Typography>
                        {existingDonation.split(',').map((donation, index) => {
                            const [amt, ref] = donation.trim().split('@');
                            return (
                                <Typography key={index} variant="body2" sx={{ fontFamily: 'monospace' }}>
                                    ₹{amt} (Ref: {ref})
                                </Typography>
                            );
                        })}
                        <Typography variant="body2" sx={{ mt: 1, color: 'secondary.main' }}>
                            Total: ₹{existingTotal}
                        </Typography>
                    </Box>
                )}

                <Box sx={{ mb: 2 }}>
                    <TextField
                        label="Amount (₹)"
                        type="text"
                        variant="outlined"
                        size="small"
                        value={amount}
                        onChange={handleAmountChange}
                        placeholder="200"
                        sx={{ mb: 2, width: '100%', mt: 1 }}
                        slotProps={{ htmlInput: { inputMode: 'numeric', pattern: '[0-9]*' } }}
                        autoFocus
                    />
                    <TextField
                        label="Transaction Reference"
                        type="text"
                        variant="outlined"
                        size="small"
                        value={txnRef}
                        onChange={(e) => setTxnRef(e.target.value)}
                        placeholder="ABC123"
                        sx={{ width: '100%' }}
                    />
                </Box>
            </DialogContent>
            <DialogActions>
                <Button onClick={onClose} color="inherit" disabled={isSubmitting}>
                    Cancel
                </Button>
                <Button onClick={handleSubmit} color="primary" variant="contained" disabled={!isValid || isSubmitting}>
                    {isSubmitting ? 'Submitting...' : 'Submit'}
                </Button>
            </DialogActions>
        </Dialog>
    );
};
