import * as React from 'react';
import { Box, TextField, InputAdornment, IconButton, CircularProgress, Menu, MenuItem, ListItemIcon, ListItemText, useMediaQuery, useTheme } from '@mui/material';
import { Search, Clear, TuneRounded, HowToRegOutlined, FactCheckOutlined } from '@mui/icons-material';
import { ApiComponentStateManager } from '@/lib/api-state';
import { SearchServices, SearchServicesError, AttendeeServices, AttendeeServicesError } from '@/api';
import { CallStatus, Validator } from '@/types/api.types';
import { StateData } from '@/store';
import { StatusMessage } from '@/components/StatusMessage';
import { ProfileCard } from '@/components/ProfileCard';
import { AttendeeCard } from './AttendeeCard';
import { PublicProfileResult } from '@/types/profile.types';
import { UnifiedSearchResult } from '@/types/search.types';
import { AttendeeData } from '@/types/attendee.types';
import { ExtractCorrelationId } from '@/utils/common';
import { useSelectedEventContext } from '@/hooks/useSelectedEventContext';
import { getEventId } from '@/constants/ApiConstants';

type Mode = 'register' | 'checkin';

interface AttendeeSearchProps {
    initialMode?: Mode;
}

export const AttendeeSearch: React.FC<AttendeeSearchProps> = ({ initialMode = 'register' }) => {
    const { selectedEvent } = useSelectedEventContext();
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

    const [mode, setMode] = React.useState<Mode>(initialMode);
    const [query, setQuery] = React.useState<string>('');
    const [searchedQuery, setSearchedQuery] = React.useState<string>('');
    const [filterAnchorEl, setFilterAnchorEl] = React.useState<null | HTMLElement>(null);

    // Register mode results (profiles via unified search)
    const [profileResults, setProfileResults] = React.useState<PublicProfileResult[]>([]);
    const [profileStatus, setProfileStatus] = React.useState<CallStatus>(CallStatus.NotStarted);
    const [profileHttpStatus, setProfileHttpStatus] = React.useState<number>(0);
    const [profileCorrelationId, setProfileCorrelationId] = React.useState<string | undefined>(undefined);
    const [registeredProfiles, setRegisteredProfiles] = React.useState<Set<string>>(new Set());

    // CheckIn mode results (attendees)
    const [attendeeList, setAttendeeList] = React.useState<StateData<AttendeeData[]>>({} as StateData<AttendeeData[]>);

    const isRegistrationEnabled = selectedEvent?.isRegistrationEnabled ?? true;
    const trimmedQuery = query.trim();
    const isPhoneValid = Validator.IsPhone(trimmedQuery);
    const canSearch = mode === 'register'
        ? trimmedQuery.length >= 2
        : isPhoneValid;

    const isSearching = mode === 'register'
        ? profileStatus === CallStatus.InProgress
        : attendeeList.status === CallStatus.InProgress;

    const filterOptions: Array<{ value: Mode; label: string; icon: React.ReactNode }> = [
        { value: 'register', label: 'Register', icon: <HowToRegOutlined fontSize="small" /> },
        { value: 'checkin', label: 'CheckIn', icon: <FactCheckOutlined fontSize="small" /> },
    ];
    const activeFilter = filterOptions.find(o => o.value === mode);

    const resetResults = () => {
        setProfileResults([]);
        setProfileStatus(CallStatus.NotStarted);
        setProfileHttpStatus(0);
        setProfileCorrelationId(undefined);
        setAttendeeList({} as StateData<AttendeeData[]>);
        setRegisteredProfiles(new Set());
    };

    const executeSearch = async () => {
        if (!canSearch) return;
        setSearchedQuery(trimmedQuery);
        if (mode === 'register') {
            setProfileStatus(CallStatus.InProgress);
            setRegisteredProfiles(new Set());
            try {
                const response = await SearchServices.UnifiedSearch(trimmedQuery, { pageNumber: 1, pageSize: 50 });
                setProfileHttpStatus(response.data.status);
                setProfileCorrelationId(ExtractCorrelationId(response));
                if (response.data.status >= 200 && response.data.status < 300) {
                    const result: UnifiedSearchResult = response.data.result;
                    setProfileResults(result.profiles?.items || []);
                    setProfileStatus(CallStatus.Success);
                } else {
                    setProfileResults([]);
                    setProfileStatus(CallStatus.Failure);
                }
            } catch {
                setProfileResults([]);
                setProfileStatus(CallStatus.Failure);
            }
        } else {
            ApiComponentStateManager(AttendeeServices.GetAttendeeByPhone(getEventId(), trimmedQuery), setAttendeeList);
        }
    };

    const handleClear = () => {
        setQuery('');
        setSearchedQuery('');
        resetResults();
    };

    const handleProfileRegister = (profileId: string) => {
        setRegisteredProfiles(prev => new Set([...prev, profileId]));
    };

    const handleCancelRegistration = (attendeeId: string) => {
        setAttendeeList(prev => ({
            ...prev,
            data: prev.data?.filter(attendee => attendee.userId !== attendeeId),
        }));
    };

    if (!selectedEvent) return null;

    const attendeeResults = attendeeList.data || [];
    const profileSuccess = profileStatus === CallStatus.Success;
    const attendeeSuccess = attendeeList.status === CallStatus.Success;

    return (
        <>
            {/* Google-style search bar with filter */}
            <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', pt: 2, pb: 2 }}>
                <Box sx={{ width: '100%', maxWidth: 580, px: isMobile ? 1 : 0 }}>
                    <TextField
                        fullWidth
                        placeholder={mode === 'register' ? 'Search profile by name, phone, batch...' : 'Search attendee by phone to check in...'}
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); executeSearch(); } }}
                        disabled={isSearching}
                        sx={{
                            '& .MuiOutlinedInput-root': {
                                borderRadius: '24px',
                                height: isMobile ? 48 : 52,
                                px: 1,
                                bgcolor: '#ffffff',
                                border: '1px solid #dfe1e5',
                                boxShadow: 'none',
                                '&:hover': { bgcolor: '#ffffff', boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)', borderColor: 'transparent' },
                                '&.Mui-focused': { bgcolor: '#ffffff', boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)', borderColor: 'transparent' },
                                '& fieldset': { border: 'none' },
                            },
                        }}
                        slotProps={{
                            input: {
                                startAdornment: (
                                    <InputAdornment position="start">
                                        <IconButton
                                            size="small"
                                            onClick={(e) => setFilterAnchorEl(e.currentTarget)}
                                            sx={{ color: '#fff', bgcolor: 'primary.main', '&:hover': { bgcolor: 'primary.dark' } }}
                                            title="Change filter"
                                        >
                                            {activeFilter?.icon ?? <TuneRounded fontSize="small" />}
                                        </IconButton>
                                    </InputAdornment>
                                ),
                                endAdornment: (
                                    <InputAdornment position="end">
                                        {query && (
                                            <IconButton size="small" onClick={handleClear} disabled={isSearching}>
                                                <Clear fontSize="small" />
                                            </IconButton>
                                        )}
                                        {isSearching ? (
                                            <CircularProgress size={20} sx={{ ml: 0.5 }} />
                                        ) : (
                                            <IconButton
                                                size="small"
                                                onClick={executeSearch}
                                                disabled={!canSearch}
                                                color="primary"
                                            >
                                                <Search />
                                            </IconButton>
                                        )}
                                    </InputAdornment>
                                ),
                            },
                            htmlInput: mode === 'checkin' ? { inputMode: 'numeric', maxLength: 15 } : { maxLength: 100 },
                        }}
                    />

                    {/* Filter Menu */}
                    <Menu
                        anchorEl={filterAnchorEl}
                        open={Boolean(filterAnchorEl)}
                        onClose={() => setFilterAnchorEl(null)}
                        slotProps={{ paper: { sx: { borderRadius: 2, mt: 0.5, minWidth: 200 } } }}
                    >
                        {filterOptions.map(option => (
                            <MenuItem
                                key={option.value}
                                selected={mode === option.value}
                                onClick={() => {
                                    if (option.value !== mode) {
                                        setMode(option.value);
                                        resetResults();
                                        setSearchedQuery('');
                                    }
                                    setFilterAnchorEl(null);
                                }}
                                sx={{ py: 1 }}
                            >
                                <ListItemIcon sx={{ minWidth: 32 }}>{option.icon}</ListItemIcon>
                                <ListItemText>{option.label}</ListItemText>
                            </MenuItem>
                        ))}
                    </Menu>
                </Box>
            </Box>

            {/* Status */}
            {mode === 'register' ? (
                <StatusMessage
                    notStartedMessage=""
                    successMessage={searchedQuery ? `${profileResults.length} result(s) found for "${searchedQuery}".` : undefined}
                    failureMessage={SearchServicesError.UnifiedSearchError(profileHttpStatus)}
                    currentStatus={profileStatus}
                    correlationId={profileCorrelationId}
                />
            ) : (
                <StatusMessage
                    notStartedMessage=""
                    successMessage={searchedQuery ? `${attendeeResults.length} result(s) found${attendeeResults.length ? ` for ${attendeeResults[0]?.profile?.phone}` : ''}.` : undefined}
                    failureMessage={AttendeeServicesError.GetAttendeeByPhoneError(attendeeList.httpStatus)}
                    currentStatus={attendeeList.status}
                    correlationId={attendeeList.correlationId}
                />
            )}

            {/* Results */}
            {mode === 'register' && profileSuccess && profileResults.length > 0 && (
                <Box
                    sx={{
                        display: 'flex',
                        flexWrap: 'wrap',
                        gap: 2,
                        mb: 2,
                        width: '100%',
                        '& > *': { flex: '1 1 auto', minWidth: '280px', maxWidth: '320px', flexBasis: 'calc(25% - 16px)' },
                        '@media (max-width: 1400px)': { '& > *': { flexBasis: 'calc(33.333% - 16px)' } },
                        '@media (max-width: 1000px)': { '& > *': { flexBasis: 'calc(50% - 16px)' } },
                        '@media (max-width: 600px)': { '& > *': { flexBasis: '100%' } },
                    }}
                >
                    {profileResults.map((profile, idx) => (
                        <ProfileCard
                            key={profile.id || idx}
                            profile={profile}
                            onRegister={handleProfileRegister}
                            isRegistered={registeredProfiles.has(profile.id)}
                            isRegistrationEnabled={isRegistrationEnabled}
                        />
                    ))}
                </Box>
            )}

            {mode === 'checkin' && attendeeSuccess && attendeeResults.length > 0 && (
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                    {attendeeResults.map((attendee, idx) => (
                        <AttendeeCard
                            key={attendee.userId || idx}
                            attendee={attendee}
                            onCancelRegistration={handleCancelRegistration}
                        />
                    ))}
                </Box>
            )}
        </>
    );
};
